         */
        long second = now.getEpochSecond();
        int offset = timeZone.getTimeZoneOffsetUTC(second);
        second += offset;
        return ValueTimestampTimeZone.fromDateValueAndNanos(dateValueFromAbsoluteDay(second / SECONDS_PER_DAY),
