    private static boolean isUpperSysIdentifier(String upperName) {
        int l = upperName.length();
        if (l == 0) {
            return false;
        }
        char c = upperName.charAt(0);
        if (c < 'A' || c > 'Z') {
            return false;
        }
        l--;
        for (int i = 1; i < l; i++) {
            c = upperName.charAt(i);
            if ((c < 'A' || c > 'Z') && c != '_') {
                return false;
            }
        }
        if (l > 0) {
            c = upperName.charAt(l);
            if (c < 'A' || c > 'Z') {
                return false;
            }
        }
        return true;
    }

